#nullable enable // autogenerated  

using MVZ2.GameContent.Buffs.Contraptions;
using MVZ2.GameContent.Detections;
using MVZ2.GameContent.Projectiles;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Contraptions;
using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Properties;
using PVZEngine.Buffs;
using PVZEngine.Entities;
using PVZEngine.Level;
using Tools;
using UnityEngine;

namespace MVZ2.GameContent.Contraptions
{
    [EntityBehaviourDefinition(VanillaContraptionNames.EXPANDispenser)]
    public class EXPANDispenser : DispenserFamily
    {
        public EXPANDispenser(string nsp, string name) : base(nsp, name)
        {
        }

        public override void Init(Entity entity)
        {
            base.Init(entity);
            InitShootTimer(entity);
            SetEvocationTimer(entity, new FrameTimer(EVOCATION_TIME));
            SetRepeatTimer(entity, new FrameTimer(REPEAT_INVERVAL));
            SetHasMissileBox(entity, false); // ГѕЪМЛЏЮЊfalse  
            SetMissileCount(entity, 0); // ГѕЪМЛЏЕМЕЏЪ§СПЮЊ0  
            SetMissileAttackTimer(entity, new FrameTimer(MISSILE_ATTACK_INTERVAL));
        }
        protected override void UpdateAI(Entity entity)
        {
            base.UpdateAI(entity);

            // ИќаТЕМЕЏЙЅЛїМЦЪБЦї    
            var missileAttackTimer = GetMissileAttackTimer(entity);
            if (missileAttackTimer != null)
            {
                missileAttackTimer.Run(entity.GetAttackSpeed());
                if (missileAttackTimer.Expired && HasMissileBox(entity))
                {
                    TryShootMissile(entity);
                    missileAttackTimer.Reset();
                }
            }

            if (!entity.IsEvoked())
            {
                ShootTick(entity);
                int repeatCount = GetRepeatCount(entity);
                if (repeatCount > 0)
                {
                    var repeatTimer = GetRepeatTimer(entity);
                    if (repeatTimer != null && repeatTimer.RunToExpired(entity.GetAttackSpeed()))
                    {
                        Shoot(entity);
                        SetRepeatCount(entity, repeatCount - 1);
                        repeatTimer.Reset();
                    }
                }
            }
            else
            {
                EvokedUpdate(entity);
            }
        }
        protected override void UpdateLogic(Entity entity)
        {
            base.UpdateLogic(entity);
            entity.SetModelProperty("Upgraded", IsUpgraded(entity));
            entity.SetModelProperty("GatlinAlt", IsGatlinAlt(entity));
            entity.SetModelProperty("MissileBox", HasMissileBox(entity));
        }
        public override void OnShootTick(Entity entity)
        {
            int count = IsUpgraded(entity) ? REPEAT_COUNT_UPGRADED : REPEAT_COUNT;
            SetRepeatCount(entity, count);
            var repeatTimer = GetRepeatTimer(entity);
            if (repeatTimer != null)
            {
                repeatTimer.ResetTime(Mathf.FloorToInt(15f / count));
                repeatTimer.Frame = 0;
            }
        }
        public override Entity? Shoot(Entity entity)
        {
            SetGatlinAlt(entity, !IsGatlinAlt(entity));
            return base.Shoot(entity);
        }

        public override bool CanTrigger(Entity entity)
        {
            // гЕгаЕМЕЏКаЪБЮоЗЈДЅЗЂ  
            if (HasMissileBox(entity))
                return false;
            return base.CanTrigger(entity);
        }

        protected override void OnTrigger(Entity entity)
        {
            base.OnTrigger(entity);

            // ДЅЗЂКѓЛёЕУЕМЕЏКа  
            SetHasMissileBox(entity, true);
            SetMissileCount(entity, MISSILE_MAX_COUNT);

            entity.PlaySound(VanillaSoundID.gunReload);
            entity.PlaySound(VanillaSoundID.powerUp);
        }

        public override bool CanEvoke(Entity entity)
        {
            return base.CanEvoke(entity);
        }
        protected override void OnEvoke(Entity entity)
        {
            base.OnEvoke(entity);

            // ДЅЗЂКѓЛёЕУЕМЕЏКа    
            SetHasMissileBox(entity, true);
            SetMissileCount(entity, MISSILE_MAX_COUNT);

            // БЃГжд­гаЕФЩ§МЖаЇЙћ  
            if (!entity.HasBuff<HFPDUpgradedBuff>())
            {
                entity.AddBuff<HFPDUpgradedBuff>();
            }
            entity.PlaySound(VanillaSoundID.motor);

            // жижУВЂЦєЖЏДѓеаМЦЪБЦї  
            var evocationTimer = GetEvocationTimer(entity);
            evocationTimer?.Reset();
            entity.SetEvoked(true);
        }

        private void TryShootMissile(Entity entity)
        {
            var missileCount = GetMissileCount(entity);
            if (missileCount <= 0)
            {
                // ЕМЕЏгУЭъЃЌвЦГ§ЕМЕЏКа    
                SetHasMissileBox(entity, false);
                return;
            }

            // ЫїЕаЩЯЁЂжаЁЂЯТШ§ЬѕЯпТЗЕФПежаЕаШЫ    
            var currentLane = entity.GetLane();
            var maxLane = entity.Level.GetMaxLaneCount();

            Entity? target = null;
            int targetLane = currentLane;

            // гХЯШЫбЫїЕБЧАЯпТЗ    
            target = FindFlyingEnemyInLane(entity, currentLane);

            // ШчЙћЕБЧАЯпТЗУЛгаЃЌЫбЫїЩЯЗНЯпТЗ    
            if (target == null && currentLane > 0)
            {
                target = FindFlyingEnemyInLane(entity, currentLane - 1);
                if (target != null)
                    targetLane = currentLane - 1;
            }

            // ШчЙћЛЙЪЧУЛгаЃЌЫбЫїЯТЗНЯпТЗ    
            if (target == null && currentLane < maxLane - 1)
            {
                target = FindFlyingEnemyInLane(entity, currentLane + 1);
                if (target != null)
                    targetLane = currentLane + 1;
            }

            if (target != null && target.Exists())
            {
                // ЗЂЩфаЁЕМЕЏ    
                ShootMissile(entity, target);
                entity.TriggerAnimation("Shoot");
                SetMissileCount(entity, missileCount - 1);

                // ЕМЕЏгУЭъЪБвЦГ§ЕМЕЏКа    
                if (GetMissileCount(entity) <= 0)
                {
                    SetHasMissileBox(entity, false);
                }
            }
        }

        private Entity? FindFlyingEnemyInLane(Entity entity, int lane)
        {
            var detector = new DispenserDetector()
            {
                ignoreLowEnemy = true,
                ignoreHighEnemy = false,
                innerLaneExpansion = 1,
                outerLaneExpansion = 1,
                colliderFilter = (self, collider) =>
                {
                    var enemy = collider.Entity;
                    // жЛМьВтПежаЕаШЫ    
                    if (!enemy.Definition.IsFlyingEnemy())
                        return false;
                    // МьВщЪЧЗёдкжИЖЈЯпТЗ    
                    if (enemy.GetLane() != lane)
                        return false;
                    return true;
                }
            };

            return detector.DetectEntityWithTheLeast(entity, e => (e.GetCenter() - entity.Position).sqrMagnitude);
        }

        private void ShootMissile(Entity entity, Entity target)
        {
            var direction = (target.GetCenter() - entity.GetShootPoint()).normalized;
            var speed = entity.GetShotVelocity().magnitude;
            var velocity = direction * speed;

            var param = entity.GetShootParams();
            param.projectileID = VanillaProjectileID.SmallRocket;
            param.damage = entity.GetDamage() * 6;
            param.velocity = velocity;

            entity.ShootProjectile(param);
            entity.PlaySound(VanillaSoundID.launch);
        }

        private void EvokedUpdate(Entity entity)
        {
            var evocationTimer = GetEvocationTimer(entity);
            if (evocationTimer == null)
                return;
            evocationTimer.Run();
            if (evocationTimer.PassedInterval(2))
            {
                // жБНгЕїгУЛљРрЗНЗЈ  
                var projectile = Shoot(entity);
                if (projectile != null)
                    projectile.Velocity *= 2;
            }
            if (evocationTimer.Expired)
            {
                entity.SetEvoked(false);
                var shootTimer = GetShootTimer(entity);
                shootTimer?.Reset();
            }
        }

        // ЕМЕЏКаЯрЙиЪєад    
        public static bool HasMissileBox(Entity entity) => entity.GetBehaviourField<bool>(PROP_HAS_MISSILE_BOX);
        public static void SetHasMissileBox(Entity entity, bool value) => entity.SetBehaviourField(PROP_HAS_MISSILE_BOX, value);
        public static int GetMissileCount(Entity entity) => entity.GetBehaviourField<int>(PROP_MISSILE_COUNT);
        public static void SetMissileCount(Entity entity, int value) => entity.SetBehaviourField(PROP_MISSILE_COUNT, value);
        public static FrameTimer? GetMissileAttackTimer(Entity entity) => entity.GetBehaviourField<FrameTimer>(PROP_MISSILE_ATTACK_TIMER);
        public static void SetMissileAttackTimer(Entity entity, FrameTimer timer) => entity.SetBehaviourField(PROP_MISSILE_ATTACK_TIMER, timer);

        public static FrameTimer? GetEvocationTimer(Entity entity) => entity.GetBehaviourField<FrameTimer>(PROP_EVOCATION_TIMER);
        public static void SetEvocationTimer(Entity entity, FrameTimer timer) => entity.SetBehaviourField(PROP_EVOCATION_TIMER, timer);
        public static FrameTimer? GetRepeatTimer(Entity entity) => entity.GetBehaviourField<FrameTimer>(PROP_REPEAT_TIMER);
        public static void SetRepeatTimer(Entity entity, FrameTimer timer) => entity.SetBehaviourField(PROP_REPEAT_TIMER, timer);

        public static bool IsGatlinAlt(Entity entity) => entity.GetBehaviourField<bool>(PROP_GATLIN_ALT);
        public static void SetGatlinAlt(Entity entity, bool value) => entity.SetBehaviourField(PROP_GATLIN_ALT, value);
        public static bool IsUpgraded(Entity entity) => entity.HasBuff<HFPDUpgradedBuff>();
        public static int GetRepeatCount(Entity entity) => entity.GetBehaviourField<int>(PROP_REPEAT_COUNT);
        public static void SetRepeatCount(Entity entity, int count) => entity.SetBehaviourField(PROP_REPEAT_COUNT, count);

        public const int REPEAT_INVERVAL = 7;
        public const int EVOCATION_TIME = 120;
        public const int REPEAT_COUNT = 8;
        public const int REPEAT_COUNT_UPGRADED = 12;
        public const int MISSILE_MAX_COUNT = 8;
        public const int MISSILE_ATTACK_INTERVAL = 45; // ЕМЕЏЙЅЛїМфИєЃЈжЁЃЉ    

        public static readonly VanillaEntityPropertyMeta<FrameTimer> PROP_EVOCATION_TIMER = new VanillaEntityPropertyMeta<FrameTimer>("EvocationTimer");
        public static readonly VanillaEntityPropertyMeta<FrameTimer> PROP_REPEAT_TIMER = new VanillaEntityPropertyMeta<FrameTimer>("RepeatTimer");
        public static readonly VanillaEntityPropertyMeta<int> PROP_REPEAT_COUNT = new VanillaEntityPropertyMeta<int>("RepeatCount");
        public static readonly VanillaEntityPropertyMeta<bool> PROP_GATLIN_ALT = new VanillaEntityPropertyMeta<bool>("gatlin_alt");
        public static readonly VanillaEntityPropertyMeta<bool> PROP_HAS_MISSILE_BOX = new VanillaEntityPropertyMeta<bool>("HasMissileBox");
        public static readonly VanillaEntityPropertyMeta<int> PROP_MISSILE_COUNT = new VanillaEntityPropertyMeta<int>("MissileCount");
        public static readonly VanillaEntityPropertyMeta<FrameTimer> PROP_MISSILE_ATTACK_TIMER = new VanillaEntityPropertyMeta<FrameTimer>("MissileAttackTimer");
    }
}